import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { LineChart } from '@mui/x-charts';
import response from './response.json';

interface CompetitorPrice {
  store: string;
  price: number;
}

interface ProductData {
  product: {
    name: string;
    currentPrice: number;
  };
  competitorPrices: CompetitorPrice[];
  priceTrend: number[];
}

export default function Widget() {
  const productData = response.data as ProductData;
  const { product, competitorPrices, priceTrend } = productData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ mb: 1, color: '#FF5722' }}>
              {product.name}
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: '#1976D2' }}>
              ${product.currentPrice.toFixed(2)}
            </Typography>
            <Typography variant="caption" color="text.secondary" sx={{ mt: 0.5 }}>
              Current Price
            </Typography>
          </Box>

          <LineChart
            height={100}
            series={[
              {
                data: priceTrend,
                color: '#FFC107',
                curve: 'linear',
                showMark: false,
              },
            ]}
            xAxis={[{ data: priceTrend.map((_, i) => i), hide: true }]}
            margin={{ top: 5, bottom: 5, left: 10, right: 10 }}
            sx={{
              '& .MuiLineElement-root': {
                strokeWidth: 2,
              },
            }}
          />

          <Stack direction="row" spacing={0.5}>
            {competitorPrices.map((competitor, index) => (
              <Chip
                key={index}
                label={`${competitor.store}: $${competitor.price.toFixed(2)}`}
                sx={{ fontSize: '11px', px: 1, py: 0.5 }}
              />
            ))}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
